ValidationRule.errorConditionFormula:
AND(
    NOT(ISPICKVAL(PendencyType__c, 'Validação')),
    NOT(CONTAINS($Profile.Name, "Admin")),
    OR(
        /* Caso 1: Usuário 5A editando "Resposta da Solicitação" em registro criado por ele ou Integração QuintoAndar */
        AND(
            LEFT($Profile.Name, LEN("CRN")) <> "CRN",
            LEFT(CreatedBy.Profile.Name, LEN("CRN")) <> "CRN",
            ISCHANGED(CommentResponse__c)),

        /* Caso 2: Usuário 5A editando "Solicitação" em registro criado por CRN */
        AND(
            LEFT($Profile.Name, LEN("CRN")) <> "CRN",
            LEFT(CreatedBy.Profile.Name, LEN("CRN")) = "CRN",
            ISCHANGED(Comments__c)),

        /* Caso 3: Usuário 5A editando "Pendência" em registro não criado por ele */
        AND(
            LEFT($Profile.Name, LEN("CRN")) <> "CRN",
            LEFT(CreatedBy.Profile.Name, LEN("CRN")) = "CRN",
            ISCHANGED(Name)
            ),

         /* Caso 4: Usuário CRN editando "Tipo de Solicitação" em registro não criado por ele */

         AND(
             LEFT($Profile.Name, LEN("CRN")) <> "CRN",
             LEFT(CreatedBy.Profile.Name, LEN("CRN")) = "CRN",
             ISCHANGED(PendencyType__c)
             ),


        /* BLOQUEIOS DE CRIAÇÃO */

        /* Criando registro: CommentResponse__c deve estar em branco */
        AND(
        ISNEW(),
        CommentResponse__c != null)
        )
        )
